CustomFunction.Calculation:
// Appends OR column IS NOT NULL.
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryConvertField_cf ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "notNull" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)
